/**
 * @summary Get a shared photo by token (no auth required)
 */
export const getGetSharedPhotoUrl = (token: string) => {
  return `/api/shares/${token}`;
};

export const getSharedPhoto = async (
  token: string,
  options?: RequestInit,
): Promise<SharedPhotoResponse> => {
  return customFetch<SharedPhotoResponse>(getGetSharedPhotoUrl(token), {
    ...options,
    method: "GET",
  });
};

export const getGetSharedPhotoQueryKey = (token: string) => {
  return [`/api/shares/${token}`] as const;
};

export const getGetSharedPhotoQueryOptions = <
  TData = Awaited<ReturnType<typeof getSharedPhoto>>,
  TError = ErrorType<void>,
>(
  token: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getSharedPhoto>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetSharedPhotoQueryKey(token);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getSharedPhoto>>> = ({
    signal,
  }) => getSharedPhoto(token, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!token,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getSharedPhoto>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetSharedPhotoQueryResult = NonNullable<
  Awaited<ReturnType<typeof getSharedPhoto>>
>;
export type GetSharedPhotoQueryError = ErrorType<void>;

/**
 * @summary Get a shared photo by token (no auth required)
 */

export function useGetSharedPhoto<
  TData = Awaited<ReturnType<typeof getSharedPhoto>>,
  TError = ErrorType<void>,
>(
  token: string,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getSharedPhoto>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetSharedPhotoQueryOptions(token, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
